use std::fs::{self, File};
use std::io::Write;
use std::time::Instant;

use sop_tabu::parser::parse_instance;
use sop_tabu::solver::phase1::phase1_construction;
use sop_tabu::solver::phase2::tabu_search;

fn main() {
    let instances_dir = "src/instances";
    let output_file = "benchmark_results.csv";

    let mut csv = File::create(output_file).expect("Failed to create CSV");
    writeln!(csv, "Instance,Profit,Cost,Time_ms").unwrap();

    let paths = fs::read_dir(instances_dir).expect("Failed to read directory");

    for path in paths {
        let path = path.unwrap().path();
        if path.extension().and_then(|s| s.to_str()) == Some("sop") {
            let filename = path.file_name().unwrap().to_str().unwrap();
            println!("Processing {}...", filename);

            let problem = parse_instance(path.to_str().unwrap());

            let start = Instant::now();

            // Phase 1
            let initial_sol = phase1_construction(&problem);

            // Phase 2 & 3 (Adjust parameters as needed: lambda, beta, alpha, max_iter)
            let best_sol = tabu_search(&problem, initial_sol, 1.0, 0.1, 10, 1000);

            let duration = start.elapsed().as_millis();

            // Save to CSV
            writeln!(
                csv, 
                "{},{},{},{}", 
                filename, 
                best_sol.total_profit, 
                best_sol.total_cost, 
                duration
            ).unwrap();
        }
    }

    println!("Benchmarking complete. Results saved to {}", output_file);
}



