use std::env;
use std::time::Instant;

use sop_tabu::parser::parse_instance;
use sop_tabu::solver::phase2::tabu_search;
use sop_tabu::solver::phase1::{phase1_construction};

fn main() {
    let args: Vec = env::args().collect();
    if args.len() < 4 {
        eprintln!("Usage: {}   ", args[0]);
        std::process::exit(1);
    }

    let file_path = &args[1];
    let max_iter: usize = args[2].parse().expect("Invalid max_iter");
    let alpha: usize = args[3].parse().expect("Invalid alpha");

    // Hyperparameters from paper
    let lambda = 0.5;
    let beta = 0.05;

    let start_time = Instant::now();

    println!("Parsing instance: {}", file_path);
    let pb = parse_instance(file_path);

    println!("Starting Phase 1 (Constructive Heuristic)...");
    let initial_sol = phase1_construction(&pb);
    println!("Phase 1 Complete -> Profit: {}, Cost: {}", initial_sol.total_profit, initial_sol.total_cost);

    println!("Starting Phase 2 (Tabu Search)...");
    let best_sol = tabu_search(&pb, initial_sol, lambda, beta, alpha, max_iter);

    let duration = start_time.elapsed();

    println!("\n=== FINAL RESULTS ===");
    println!("Execution Time: {:.2?}", duration);
    println!("Best Profit: {}", best_sol.total_profit);
    println!("Best Cost: {}", best_sol.total_cost);
    println!("Clusters Visited: {:?}", best_sol.tour_clusters);
}



#[derive(Clone)]
pub struct Problem {
    pub num_nodes: usize,
    pub num_clusters: usize,
    pub t_max: f64,
    pub dist: Vec, // Flattened 1D matrix for cache speed
    pub cluster_of_node: Vec,
    pub nodes_of_cluster: Vec<Vec>,
    pub profits: Vec,
}

impl Problem {
    #[inline(always)]
    pub fn get_dist(&self, i: usize, j: usize) -> f64 {
        self.dist[i * self.num_nodes + j]
    }
}

#[derive(Clone, Debug)]
pub struct Solution {
    pub tour_nodes: Vec,       
    pub tour_clusters: Vec,    
    pub total_profit: f64,
    pub total_cost: f64,
}

impl Solution {
    pub fn new() -> Self {
        Self {
            tour_nodes: vec![0, 0],
            tour_clusters: vec![0, 0],
            total_profit: 0.0,
            total_cost: 0.0,
        }
    }

    pub fn recompute(&mut self, pb: &Problem) {
        self.total_cost = 0.0;
        self.total_profit = 0.0;
        for i in 0..(self.tour_nodes.len() - 1) {
            self.total_cost += pb.get_dist(self.tour_nodes[i], self.tour_nodes[i + 1]);
        }
        for &c in self.tour_clusters.iter().take(self.tour_clusters.len() - 1) {
            if c != 0 {
                self.total_profit += pb.profits[c];
            }
        }
    }
}



